// Thin helper for talking to Supabase's auto-generated REST API (PostgREST).
// token is only needed for admin (logged-in) requests; public storefront reads/writes omit it.
async function sbRequest(path, { method = 'GET', token, body } = {}) {
  const headers = { apikey: SUPABASE_ANON_KEY, 'Content-Type': 'application/json' };
  if (token) headers.Authorization = `Bearer ${token}`;
  if (method !== 'GET') headers.Prefer = 'return=representation';
  const res = await fetch(`${SUPABASE_URL}/rest/v1${path}`, {
    method, headers, body: body !== undefined ? JSON.stringify(body) : undefined,
  });
  if (!res.ok) {
    const errText = await res.text().catch(() => '');
    throw new Error(errText || `Request failed (${res.status})`);
  }
  if (res.status === 204) return null;
  return res.json();
}

// Email/password login against Supabase Auth. Returns { access_token, user }.
async function sbLogin(email, password) {
  const res = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=password`, {
    method: 'POST',
    headers: { apikey: SUPABASE_ANON_KEY, 'Content-Type': 'application/json' },
    body: JSON.stringify({ email, password }),
  });
  const data = await res.json();
  if (!res.ok) throw new Error(data.error_description || data.msg || 'Login failed');
  return data;
}

