// Builds a compact order summary that fits PayFast's 255-character item_description field.
function buildItemDescription(cart, form, orderNumber) {
  const itemsPart = cart.map((li) => {
    const extras = li.addons.length ? `+${li.addons.length} extra` : '';
    return `${li.dollName}(${li.gender === 'girl' ? 'Girl' : 'Boy'},${li.outfit.name}${extras ? ',' + extras : ''})x${li.qty}`;
  }).join('; ');
  const contact = form.phone || form.email;
  const delivery = form.deliveryMethod === 'pudo'
    ? `PUDO locker: ${form.pudoLocker}, ${form.city}`
    : `${form.address}, ${form.city} ${form.zip}`;
  let desc = `Ref ${orderNumber} | ${itemsPart} | ${form.name}, ${contact} | ${delivery}`;
  if (desc.length > 255) desc = desc.slice(0, 252) + '...';
  return desc;
}

// Submits a one-off hidden form to PayFast. No JSX <form> element is used,
// this is built directly in the DOM only at the moment of payment.
function redirectToPayfast(fields) {
  const form = document.createElement('form');
  form.method = 'POST';
  form.action = PAYFAST_PROCESS_URL;
  Object.entries(fields).forEach(([key, value]) => {
    if (value === undefined || value === null || value === '') return;
    const input = document.createElement('input');
    input.type = 'hidden';
    input.name = key;
    input.value = value;
    form.appendChild(input);
  });
  document.body.appendChild(form);
  form.submit();
}

